import * as React from 'react';
import clsx from 'clsx';
import RotateOutlined from '@universe-design/icons-react/RotateOutlined';
import { useEventCallback } from '@universe-design/react-utilities';
import { mat2d, vec2 } from 'gl-matrix';
import { useLocaleReceiver } from '../../config-provider/hooks';
import { ROTATION_RADIAN } from '../constants';
import { IconButton } from '../../button';
import { Tooltip } from '../../tooltip';
import { useImageViewerContext } from '../ImageViewerContext';

import '../style';

/**
 * 图片查看器旋转工具 hook
 *
 * @public
 */
export const useImageViewerToolbarRotation = (): {
  /**
   * 逆时针旋转图片
   */
  rotateCounterclockwise: () => void;
} => {
  const { getContainerRect, setMatrixByPoints } = useImageViewerContext();

  return {
    rotateCounterclockwise: useEventCallback(() => {
      const containerRect = getContainerRect();

      const origin = vec2.fromValues(
        (containerRect.x + containerRect.width) / 2,
        (containerRect.y + containerRect.height) / 2,
      );

      const rotationMat = mat2d.fromRotation(mat2d.create(), ROTATION_RADIAN);

      setMatrixByPoints(absolutePoint => {
        const point = vec2.subtract(vec2.create(), absolutePoint, origin); // 基于 origin 的坐标
        let nextPoint = vec2.create();
        nextPoint = vec2.transformMat2d(vec2.create(), point, rotationMat);
        nextPoint = vec2.add(vec2.create(), nextPoint, origin);
        return nextPoint;
      });
    }),
  };
};

export const Rotation = () => {
  const locale = useLocaleReceiver('imageViewer');
  const { rootCssScope } = useImageViewerContext();

  const { rotateCounterclockwise } = useImageViewerToolbarRotation();

  return (
    <Tooltip title={locale.rotate} overlayClassName={rootCssScope('__toolbar__tooltip')}>
      <IconButton
        size={20}
        icon={<RotateOutlined />}
        className={clsx(rootCssScope('__toolbar__button'), rootCssScope('__toolbar__rotation'))}
        onClick={rotateCounterclockwise}
      />
    </Tooltip>
  );
};
